/**
 * Context shape consumed by <RichSidebarTrigger> (C7), prefab parts
 * (<NavBrand>, <NavUser>, <NavBadge>) (C6/C9), and any consumer-rendered
 * descendant that wants to read sidebar state without prop drilling.
 *
 * L40: each <RichSidebar> creates its own provider scoped to its subtree,
 * so multi-instance pages get isolated contexts automatically. <Trigger>
 * reads the NEAREST provider (standard React context behavior).
 *
 * The context value is `null` when there's no provider above — descendants
 * MUST handle this (e.g., <Trigger> falls back to disabled + dev warn;
 * <NavBadge> falls back to position="inline-end" per L46).
 */
export interface RichSidebarContextValue {
  // Latest reducer state — descendants read here, not via prop drilling
  state: SidebarReducerState;

  // Dispatch — descendants use this to mutate (e.g., <Trigger> dispatches TOGGLE_MOBILE)
  dispatch: React.Dispatch<SidebarReducerAction>;

  // Imperative handle — same surface as the <RichSidebar ref={...}>
  // (descendants like <Trigger> use this when they're given an explicit `controls` prop)
  handle: RichSidebarHandle;

  // Element id of the sidebar — `<Trigger aria-controls>` hooks into this
  sidebarId: string;
}

export const RichSidebarContext = createContext<RichSidebarContextValue | null>(null);
RichSidebarContext.displayName = "RichSidebarContext";

/** Internal helper — returns the context value or null. Used by prefab parts + trigger. */
export function useRichSidebarContextOrNull(): RichSidebarContextValue | null {
  return useContext(RichSidebarContext);
}

import { useMemo } from "react";
import { computeActiveItem, type ActiveItemResult } from "../lib/compute-active-item";
import { deriveVisibleEntries, type VisibleEntriesResult } from "../lib/derive-visible-entries";
import type { NavEntry, NavItem } from "../types";

interface UseActiveDetectionOptions {
  items: ReadonlyArray<NavEntry>;
  currentPath: string;
  isActive?: (item: NavItem, currentPath: string) => boolean;
  defaultMatch?: "exact" | "prefix";
  permissions?: ReadonlySet<string>;
  keepEmptySections?: boolean;
  // v0.2.0 — gates threaded to deriveVisibleEntries (L44 / L45 / Q21).
  isOwner?: boolean;
  currentMaxMembers?: number;
  bypassFiltering?: boolean;
}

export interface UseActiveDetectionResult {
  visible: VisibleEntriesResult;
  active: ActiveItemResult;
}

/**
 * Memoize the items[] → visible-entries → active-item pipeline.
 *
 * Reference stability of `items` is critical (L34) — non-memoized items[]
 * invalidate this memo every render. Guide.md teaches consumers to memoize.
 *
 * v0.2.0 — also threads `isOwner`, `currentMaxMembers`, `bypassFiltering`
 * into the deriveVisibleEntries call (L44–L46 + Q21).
 */
export function useActiveDetection(
  options: UseActiveDetectionOptions,
): UseActiveDetectionResult {
  const visible = useMemo(
    () =>
      deriveVisibleEntries({
        items: options.items,
        permissions: options.permissions,
        keepEmptySections: options.keepEmptySections,
        isOwner: options.isOwner,
        currentMaxMembers: options.currentMaxMembers,
        bypassFiltering: options.bypassFiltering,
      }),
    [
      options.items,
      options.permissions,
      options.keepEmptySections,
      options.isOwner,
      options.currentMaxMembers,
      options.bypassFiltering,
    ],
  );

  const active = useMemo(
    () =>
      computeActiveItem({
        entries: visible.entries,
        currentPath: options.currentPath,
        isActive: options.isActive,
        defaultMatch: options.defaultMatch,
      }),
    [visible.entries, options.currentPath, options.isActive, options.defaultMatch],
  );

  return { visible, active };
}

import { useCallback, useSyncExternalStore } from "react";

/**
 * SSR-safe matchMedia hook via `useSyncExternalStore`.
 *
 * Server snapshot returns `false` (matches the SSR HTML). Client snapshot
 * reads `window.matchMedia(query).matches`. Subscribe wires the change
 * event. This avoids the React-19 cascading-render antipattern
 * (setState-in-effect) — `useSyncExternalStore` is the right primitive
 * for synchronizing with browser APIs.
 *
 * IMPORTANT (L44): Mobile-vs-desktop RENDERING is gated by CSS classes
 * (`hidden lg:flex` etc.), NOT by this hook. This hook is for JS BEHAVIOR
 * gating only — e.g., deciding whether `autoCloseMobileOnNavigate` should
 * trigger when an item is clicked. The SSR-default `false` is harmless
 * because CSS owns the visual decision.
 */
export function useMatchMedia(query: string): boolean {
  const subscribe = useCallback(
    (callback: () => void) => {
      if (typeof window === "undefined" || !window.matchMedia) return () => {};
      const mql = window.matchMedia(query);
      if (typeof mql.addEventListener === "function") {
        mql.addEventListener("change", callback);
        return () => mql.removeEventListener("change", callback);
      }
      // Safari < 14 fallback
      mql.addListener(callback);
      return () => mql.removeListener(callback);
    },
    [query],
  );

  const getSnapshot = useCallback(() => {
    if (typeof window === "undefined" || !window.matchMedia) return false;
    return window.matchMedia(query).matches;
  }, [query]);

  const getServerSnapshot = useCallback(() => false, []);

  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

// Tailwind v4 default breakpoints (px). Used to translate the enum
// values `"sm" | "md" | "lg" | "xl" | "2xl"` to CSS media queries.
export const TAILWIND_BREAKPOINTS = {
  sm: 640,
  md: 768,
  lg: 1024,
  xl: 1280,
  "2xl": 1536,
} as const;

/** Resolve a `mobileBreakpoint` prop value to a CSS media query string. */
export function resolveBreakpointQuery(
  bp: "sm" | "md" | "lg" | "xl" | "2xl" | (string & {}),
): string {
  if (bp in TAILWIND_BREAKPOINTS) {
    const px = TAILWIND_BREAKPOINTS[bp as keyof typeof TAILWIND_BREAKPOINTS];
    return `(max-width: ${px - 1}px)`;
  }
  // Raw CSS query passed through (PQ7 union with raw string)
  return bp;
}

"use client";

import { useEffect, useMemo } from "react";
import type {
  NavEntry,
  NavItem,
  RichSidebarHandle,
  RichSidebarStateValue,
  UseRichSidebarStateOptions,
} from "../types";
import { useActiveDetection } from "./use-active-detection";
import { useSidebarReducer } from "./use-sidebar-reducer";
import { useStorageSync } from "./use-storage-sync";

/**
 * Headless state hook — public API (L16).
 *
 * Returns a RichSidebarStateValue (superset of RichSidebarHandle plus
 * live state fields). Consumers using slots heavily OR building their
 * own UI lift state via this hook and pass it back to `<RichSidebar>`
 * via the `state` prop (which wins over individual props per L30).
 *
 * `<RichSidebar>` calls this hook internally too — the public hook is
 * the durable composition seam, not a parallel state machine.
 */
export function useRichSidebarState(
  options: UseRichSidebarStateOptions = {},
): RichSidebarStateValue {
  const items = options.items ?? EMPTY_ITEMS;

  // Section-collapse init priority: explicit prop > per-section
  // defaultCollapsed field. Storage rehydration outranks both via
  // EXTERNAL_SYNC after mount.
  const initialCollapsedSectionIds = useMemo(() => {
    if (options.defaultCollapsedSectionIds) {
      return options.defaultCollapsedSectionIds;
    }
    const fromItems: string[] = [];
    for (const entry of items) {
      if (entry.kind === "section" && entry.defaultCollapsed) {
        fromItems.push(entry.id);
      }
    }
    return fromItems;
  }, [options.defaultCollapsedSectionIds, items]);

  const { state, dispatch } = useSidebarReducer({
    defaultCollapsed: options.defaultCollapsed,
    defaultMobileOpen: options.defaultMobileOpen,
    defaultCollapsedSectionIds: initialCollapsedSectionIds,
  });

  // localStorage opt-in
  useStorageSync(state, dispatch, options.storageKey);

  // Active detection (filtered visible entries + active item)
  const { visible, active } = useActiveDetection({
    items,
    currentPath: options.currentPath ?? "",
    isActive: options.isActive,
    defaultMatch: options.defaultMatch,
    permissions: options.permissions,
  });

  // F1 — auto-expand section containing the active item (L48-b)
  const autoExpandActiveSection = options.autoExpandActiveSection ?? true;
  useEffect(() => {
    if (!autoExpandActiveSection) return;
    if (!active.sectionId) return;
    if (!state.collapsedSectionIds.has(active.sectionId)) return;
    dispatch({
      type: "SET_SECTION_COLLAPSED",
      sectionId: active.sectionId,
      collapsed: false,
    });
  }, [
    autoExpandActiveSection,
    active.sectionId,
    state.collapsedSectionIds,
    dispatch,
  ]);

  // Build the imperative handle (two-step to break recursive type cycle)
  const handle = useMemo<RichSidebarHandle>(() => {
    const itemsLookup = new Map<string, NavItem>();
    for (const entry of visible.entries) {
      if (entry.kind === "section") {
        for (const child of entry.items) itemsLookup.set(child.id, child);
      } else if (entry.kind !== "separator") {
        itemsLookup.set(entry.id, entry);
      }
    }

    const methods: Omit<RichSidebarHandle, "getState"> = {
      // Collapse
      toggleCollapse: () => dispatch({ type: "TOGGLE_COLLAPSED" }),
      setCollapsed: (next) => dispatch({ type: "SET_COLLAPSED", collapsed: next }),
      isCollapsed: () => state.collapsed,
      // Mobile drawer
      openMobile: () =>
        dispatch({ type: "SET_MOBILE_OPEN", open: true, reason: "imperative" }),
      closeMobile: () =>
        dispatch({ type: "SET_MOBILE_OPEN", open: false, reason: "imperative" }),
      toggleMobile: () => dispatch({ type: "TOGGLE_MOBILE" }),
      isMobileOpen: () => state.mobileOpen,
      // Section state
      toggleSection: (sectionId) => dispatch({ type: "TOGGLE_SECTION", sectionId }),
      expandSection: (sectionId) =>
        dispatch({ type: "SET_SECTION_COLLAPSED", sectionId, collapsed: false }),
      collapseSection: (sectionId) =>
        dispatch({ type: "SET_SECTION_COLLAPSED", sectionId, collapsed: true }),
      expandAllSections: () =>
        dispatch({ type: "EXPAND_ALL_SECTIONS", allSectionIds: [] }),
      collapseAllSections: () => {
        const ids = items
          .filter((e) => "kind" in e && e.kind === "section")
          .map((e) => (e as { id: string }).id);
        dispatch({ type: "COLLAPSE_ALL_SECTIONS", allSectionIds: ids });
      },
      isSectionCollapsed: (id) => state.collapsedSectionIds.has(id),
      // Items + active
      getItems: () => items,
      getItemById: (id) => itemsLookup.get(id),
      getActiveItem: () => active.item ?? undefined,
      // Focus — stub until C11 keyboard handler lands
      focusItem: (itemId) => dispatch({ type: "FOCUS_ITEM", itemId }),
      focusFirstItem: () => dispatch({ type: "FOCUS_ITEM", itemId: null }),
      focusLastItem: () => dispatch({ type: "FOCUS_ITEM", itemId: null }),
    };

    const handleObj: RichSidebarHandle = {
      ...methods,
      getState: (): RichSidebarStateValue => ({
        ...handleObj,
        collapsed: state.collapsed,
        mobileOpen: state.mobileOpen,
        collapsedSectionIds: state.collapsedSectionIds,
        activeItemId: active.item?.id ?? null,
        activeItem: active.item,
        visibleEntries: visible.entries,
      }),
    };
    return handleObj;
  }, [state, dispatch, items, visible, active]);

  return useMemo<RichSidebarStateValue>(
    () => ({
      ...handle,
      collapsed: state.collapsed,
      mobileOpen: state.mobileOpen,
      collapsedSectionIds: state.collapsedSectionIds,
      activeItemId: active.item?.id ?? null,
      activeItem: active.item,
      visibleEntries: visible.entries,
    }),
    [handle, state, active, visible],
  );
}

const EMPTY_ITEMS: ReadonlyArray<NavEntry> = [];

import { useReducer, useEffect, useRef, useCallback } from "react";
import {
  type SidebarReducerAction,
  type SidebarReducerInitOptions,
  type SidebarReducerState,
  createInitialState,
  sidebarReducer,
} from "../lib/sidebar-reducer";
import type { RichSidebarEventArgs } from "../types";

export interface UseSidebarReducerOptions extends SidebarReducerInitOptions {
  // Controlled-mode props (when provided, drive state via EXTERNAL_SYNC)
  isCollapsed?: boolean;
  isMobileOpen?: boolean;

  // Defense 1 — microtask-defer for these
  onCollapsedChange?: (args: RichSidebarEventArgs["collapsedChange"]) => void;
  onMobileOpenChange?: (args: RichSidebarEventArgs["mobileOpenChange"]) => void;
}

export interface UseSidebarReducerResult {
  state: SidebarReducerState;
  dispatch: React.Dispatch<SidebarReducerAction>;
}

/**
 * Internal reducer hook.
 *
 * Three-defenses controlled-mode wiring (L7):
 *   • Defense 1 — microtask-defer onCollapsedChange / onMobileOpenChange callbacks
 *     so consumers that synchronously sync to other state can't re-enter the reducer.
 *   • Defense 2 — content-equality short-circuit on EXTERNAL_SYNC (handled inside
 *     reducer's `EXTERNAL_SYNC` case via `lastSyncedSnapshot` check).
 *   • Defense 3 — N/A for discrete boolean state (no continuous flow to suppress).
 *
 * NOT exported from index.ts — purely internal.
 */
export function useSidebarReducer(
  options: UseSidebarReducerOptions = {},
): UseSidebarReducerResult {
  const [state, dispatch] = useReducer(
    sidebarReducer,
    {
      defaultCollapsed: options.defaultCollapsed,
      defaultMobileOpen: options.defaultMobileOpen,
      defaultCollapsedSectionIds: options.defaultCollapsedSectionIds,
    },
    createInitialState,
  );

  // Latest-ref pattern for callbacks (avoid stale closures in microtask defers)
  const onCollapsedChangeRef = useRef(options.onCollapsedChange);
  const onMobileOpenChangeRef = useRef(options.onMobileOpenChange);
  useEffect(() => {
    onCollapsedChangeRef.current = options.onCollapsedChange;
    onMobileOpenChangeRef.current = options.onMobileOpenChange;
  });

  // Controlled-mode → reducer sync (Defense 2 short-circuit inside reducer)
  useEffect(() => {
    if (options.isCollapsed === undefined && options.isMobileOpen === undefined) {
      return;
    }
    dispatch({
      type: "EXTERNAL_SYNC",
      collapsed: options.isCollapsed ?? state.collapsed,
      mobileOpen: options.isMobileOpen ?? state.mobileOpen,
    });
    // Intentionally NOT including state.* — this effect ONLY fires on controlled
    // prop changes; internal state changes shouldn't loop back through here.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [options.isCollapsed, options.isMobileOpen]);

  // Defense 1 — fire change callbacks via microtask defer when state mutates.
  // Skipped when state matches lastSyncedSnapshot (= the change came from
  // EXTERNAL_SYNC, not an internal action → consumer already knows).
  const prevCollapsedRef = useRef(state.collapsed);
  const prevMobileOpenRef = useRef(state.mobileOpen);
  useEffect(() => {
    if (prevCollapsedRef.current !== state.collapsed) {
      const next = state.collapsed;
      prevCollapsedRef.current = next;
      // Skip if this transition came from EXTERNAL_SYNC (consumer originated it)
      if (state.lastSyncedSnapshot.collapsed !== next) {
        queueMicrotask(() => {
          onCollapsedChangeRef.current?.({ collapsed: next });
        });
      }
    }
    if (prevMobileOpenRef.current !== state.mobileOpen) {
      const next = state.mobileOpen;
      prevMobileOpenRef.current = next;
      if (state.lastSyncedSnapshot.mobileOpen !== next) {
        // Reason embedded in the action; the effect can't recover it.
        // Workaround: a separate effect could subscribe to a queue of reasons,
        // but at this commit (C2) the firing is reason-less. C3+ will refine.
        queueMicrotask(() => {
          onMobileOpenChangeRef.current?.({
            open: next,
            reason: "imperative",
          });
        });
      }
    }
  }, [state.collapsed, state.mobileOpen, state.lastSyncedSnapshot]);

  // Stable dispatch (useReducer's dispatch is already stable; wrap for symmetry)
  const stableDispatch = useCallback<React.Dispatch<SidebarReducerAction>>(
    (action) => dispatch(action),
    [],
  );

  return { state, dispatch: stableDispatch };
}

"use client";

import { useEffect, useRef } from "react";
import type { SidebarReducerAction, SidebarReducerState } from "../lib/sidebar-reducer";
import {
  STORAGE_SCHEMA_VERSION,
  type StoredState,
  isStoredState,
} from "../lib/storage-schema";

/**
 * Opt-in localStorage persistence for collapse + collapsed-sections state.
 *
 * Rules (L23):
 *  • No-op when `storageKey` is undefined or `window` is unavailable (SSR).
 *  • Read on mount via useEffect — never during render (SSR-safe).
 *  • Write on state change, debounced 50ms (rapid section-toggle spam
 *    doesn't thrash localStorage).
 *  • mobileOpen is NOT persisted (transient UI, not user-preference).
 *  • Schema-versioned JSON; mismatch silently drops the stored payload.
 *  • Quota / serialization failures silently swallowed.
 */
export function useStorageSync(
  state: SidebarReducerState,
  dispatch: React.Dispatch<SidebarReducerAction>,
  storageKey: string | undefined,
): void {
  const hasReadRef = useRef(false);
  const writeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Read once on mount (or when storageKey changes)
  useEffect(() => {
    if (!storageKey || typeof window === "undefined") return;
    if (hasReadRef.current) return;
    hasReadRef.current = true;
    try {
      const raw = window.localStorage.getItem(storageKey);
      if (!raw) return;
      const parsed: unknown = JSON.parse(raw);
      if (!isStoredState(parsed)) return;
      dispatch({
        type: "EXTERNAL_SYNC",
        collapsed: parsed.collapsed,
        mobileOpen: state.mobileOpen,
      });
      // Replay collapsedSectionIds via individual SET actions so each
      // section's state lands through the reducer cleanly.
      parsed.collapsedSectionIds.forEach((id) => {
        dispatch({ type: "SET_SECTION_COLLAPSED", sectionId: id, collapsed: true });
      });
    } catch {
      // Corrupted storage — silently fall back to defaults.
    }
    // Intentionally only re-runs when storageKey changes.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [storageKey]);

  // Debounced write on state change
  useEffect(() => {
    if (!storageKey || typeof window === "undefined") return;
    if (!hasReadRef.current) return; // don't write before initial read
    if (writeTimerRef.current) clearTimeout(writeTimerRef.current);
    writeTimerRef.current = setTimeout(() => {
      const payload: StoredState = {
        v: STORAGE_SCHEMA_VERSION,
        collapsed: state.collapsed,
        collapsedSectionIds: [...state.collapsedSectionIds],
      };
      try {
        window.localStorage.setItem(storageKey, JSON.stringify(payload));
      } catch {
        // Quota or serialization failure — silently ignored.
      }
    }, 50);

    return () => {
      if (writeTimerRef.current) clearTimeout(writeTimerRef.current);
    };
  }, [storageKey, state.collapsed, state.collapsedSectionIds]);
}

import { useMemo } from "react";
import { deriveVisibleEntries } from "../lib/derive-visible-entries";
import type { NavEntry } from "../types";

export interface UseFilteredNavSectionsOpts {
  sections: ReadonlyArray<NavEntry>;
  permissions?: ReadonlySet<string>;
  isOwner?: boolean;
  currentMaxMembers?: number;
  bypassFiltering?: boolean;
}

/**
 * Pure helper hook — returns the filtered `NavEntry[]` with all three
 * gates applied (permission ∩ ownerOnly ∩ minMembers per L46) and empty
 * sections dropped. `bypassFiltering: true` skips the three permission
 * gates at BOTH section + item levels; `hidden: true` is unconditionally
 * respected (Q21).
 *
 * **Memoized over 5 inputs (Q16)** — returns referentially-stable sections
 * when inputs don't change by reference (or value, for boolean/number).
 * Mitigates R14: downstream `<NavSection>` memoization holds.
 *
 * **Consumer-side memo guidance (Finding 6 / R16):** `permissions` is a
 * `ReadonlySet<string>` — wrap construction in `useMemo([source])` on the
 * caller side, else the hook's memo will invalidate every render.
 *
 * Items-only return per PQ1 — diagnostic struct stays internal to
 * `<RichSidebar>`. NOT coupled to the `<RichSidebar>` component; consumers
 * rendering their own arbitrary sidebar UI use this standalone.
 */
export function useFilteredNavSections(
  opts: UseFilteredNavSectionsOpts,
): ReadonlyArray<NavEntry> {
  const { sections, permissions, isOwner, currentMaxMembers, bypassFiltering } = opts;

  return useMemo(
    () =>
      deriveVisibleEntries({
        items: sections,
        permissions,
        isOwner,
        currentMaxMembers,
        bypassFiltering,
      }).entries,
    [sections, permissions, isOwner, currentMaxMembers, bypassFiltering],
  );
}

import type { RichSidebarProps } from "../types";

type Variant = NonNullable<RichSidebarProps["activeVariant"]>;

/**
 * Per-variant Tailwind class composition (L12 + L17).
 *
 * Returns the class string for the link element based on:
 *  - the chosen `activeVariant`
 *  - whether the row is active or not
 *
 * renderItem slot (L13) bypasses this helper entirely — the slot decides
 * how to paint active state.
 */
export function getActiveVariantClasses(
  variant: Variant | undefined,
  isActive: boolean,
): string {
  if (!isActive) {
    return "text-foreground hover:bg-muted";
  }

  switch (variant ?? "fill") {
    case "fill":
      return "bg-(--ilinxa-nav-active-bg) text-(--ilinxa-nav-active-fg)";

    case "left-bar":
      return [
        "relative text-(--ilinxa-nav-active-bg)",
        "before:absolute before:left-0 before:top-1.5 before:bottom-1.5",
        "before:w-(--ilinxa-nav-active-bar-w) before:rounded-r-full",
        "before:bg-(--ilinxa-nav-active-bg)",
      ].join(" ");

    case "right-bar":
      return [
        "relative text-(--ilinxa-nav-active-bg)",
        "after:absolute after:right-0 after:top-1.5 after:bottom-1.5",
        "after:w-(--ilinxa-nav-active-bar-w) after:rounded-l-full",
        "after:bg-(--ilinxa-nav-active-bg)",
      ].join(" ");

    case "outline":
      return "ring-2 ring-inset ring-(--ilinxa-nav-active-bg) text-(--ilinxa-nav-active-bg)";

    case "subtle":
      return "bg-accent/30 text-foreground font-semibold";

    default:
      return "bg-(--ilinxa-nav-active-bg) text-(--ilinxa-nav-active-fg)";
  }
}

/**
 * Format a NavBadge `value` for display.
 *
 * - Numbers > max render as "{max}+" (cap overflow)
 * - Numbers ≤ max render as `String(value)`
 * - Non-numbers pass through unchanged (consumer supplied a string / ReactNode)
 * - Zero is filtered upstream by `<NavBadge>` via `showZero` flag — not handled here.
 */
export function formatBadgeValue(
  value: number | string,
  max: number,
): string {
  if (typeof value === "number") {
    return value > max ? `${max}+` : String(value);
  }
  return value;
}

import type { NavEntry, NavItem } from "../types";

export interface ActiveItemResult {
  item: NavItem | null;
  // Section ID the active item lives inside (null = top-level)
  sectionId: string | null;
}

interface ComputeOptions {
  // Already-filtered visible entries (post-permissions, post-hidden)
  entries: ReadonlyArray<NavEntry>;
  currentPath: string;
  isActive?: (item: NavItem, currentPath: string) => boolean;
  defaultMatch?: "exact" | "prefix";
}

/**
 * Compute the active NavItem given a currentPath.
 *
 * Resolution order (L9):
 *   1. `isActive` predicate (if supplied) wins for every item.
 *   2. Per-item `match: "exact" | "prefix"` fallback.
 *   3. `defaultMatch` (default "exact") for items without `match`.
 *
 * Tie-break (L42): longest matching `item.href` wins for prefix matches.
 */
export function computeActiveItem(opts: ComputeOptions): ActiveItemResult {
  const { entries, currentPath, isActive, defaultMatch = "exact" } = opts;

  // Flatten: track each NavItem alongside its containing sectionId (null if top-level).
  const flat: { item: NavItem; sectionId: string | null }[] = [];
  for (const entry of entries) {
    if (entry.kind === "section") {
      for (const child of entry.items) {
        if (child.disabled) continue;
        flat.push({ item: child, sectionId: entry.id });
      }
    } else if (entry.kind === "separator") {
      continue;
    } else {
      if (entry.disabled) continue;
      flat.push({ item: entry, sectionId: null });
    }
  }

  if (isActive) {
    // Predicate wins; first match in flat order.
    for (const { item, sectionId } of flat) {
      if (isActive(item, currentPath)) return { item, sectionId };
    }
    return { item: null, sectionId: null };
  }

  // Exact pass first — any exact match wins immediately (cheaper than longest-prefix)
  for (const { item, sectionId } of flat) {
    const mode = item.match ?? defaultMatch;
    if (mode === "exact" && item.href === currentPath) {
      return { item, sectionId };
    }
  }

  // Prefix pass — collect all prefix candidates, pick longest href.
  let best: { item: NavItem; sectionId: string | null; length: number } | null = null;
  for (const { item, sectionId } of flat) {
    const mode = item.match ?? defaultMatch;
    if (mode !== "prefix" || !item.href) continue;
    // True prefix: currentPath starts with href + (next char is "/" or end)
    if (!currentPath.startsWith(item.href)) continue;
    const after = currentPath.charAt(item.href.length);
    if (after !== "" && after !== "/") continue;
    const length = item.href.length;
    if (!best || length > best.length) best = { item, sectionId, length };
  }

  if (best) return { item: best.item, sectionId: best.sectionId };
  return { item: null, sectionId: null };
}

/**
 * Derive 2-character avatar fallback initials from a name (L35).
 *
 * Examples:
 *   "Ahmet Kaya"      → "AK"
 *   "Slack"           → "SL"
 *   "  spaced  out  " → "SO"
 *   ""                → "?"
 *   "🙃 emoji"         → "🙃E"  (preserves leading char graceful for emoji)
 */
export function deriveAvatarFallback(name: string | undefined | null): string {
  if (!name) return "?";
  const words = name.trim().split(/\s+/).filter(Boolean);
  if (words.length === 0) return "?";
  if (words.length === 1) {
    return words[0].slice(0, 2).toUpperCase();
  }
  return (words[0][0] + words[1][0]).toUpperCase();
}

import type { CSSProperties } from "react";
import type { RichSidebarProps } from "../types";

/**
 * Build the inline-style object that sets the component's CSS variables
 * on the <nav> root. Consumer CSS at any ancestor scope wins via cascade;
 * consumer props win over defaults (L11 + L16).
 */
export function deriveCssVars(
  props: Pick<
    RichSidebarProps,
    "collapsedWidth" | "expandedWidth" | "transitionDuration"
  >,
): CSSProperties {
  return {
    "--ilinxa-sidebar-w-collapsed": props.collapsedWidth ?? "5rem",
    "--ilinxa-sidebar-w-expanded": props.expandedWidth ?? "16rem",
    "--ilinxa-sidebar-transition-duration": props.transitionDuration ?? "300ms",
    "--ilinxa-sidebar-row-h": "2.75rem",
    "--ilinxa-sidebar-row-gap": "0.25rem",
    "--ilinxa-sidebar-px": "0.75rem",
    "--ilinxa-nav-active-bg": "var(--primary)",
    "--ilinxa-nav-active-fg": "var(--primary-foreground)",
    "--ilinxa-nav-active-bar-w": "3px",
    "--ilinxa-nav-badge-size": "1.25rem",
    "--ilinxa-nav-indent-step": "0.75rem",
  } as CSSProperties;
}

import type { NavEntry, NavItem, NavSection } from "../types";

export interface VisibleEntriesResult {
  // Filtered + ordered for render. Sections retain their inner items[]
  // already-filtered. Separators pass through.
  entries: ReadonlyArray<NavEntry>;

  // Diagnostic — which items dropped due to which gate. Used by
  // onPermissionDenied diff-firing (L38).
  filteredByPermission: ReadonlyArray<{ item: NavItem; requiredPermission: string }>;

  // Total NavItem count BEFORE filtering (for the empty-state "no-items" branch).
  totalItemCount: number;

  // Count of items that exist but were hidden (manual `hidden: true`).
  hiddenItemCount: number;
}

interface DeriveOptions {
  items: ReadonlyArray<NavEntry>;
  permissions?: ReadonlySet<string>;
  keepEmptySections?: boolean;
  /**
   * v0.2.0 — Whether the current user is an owner. Used by `ownerOnly`
   * gate (L44). Default `false` (matches v0.1 behavior — no items have
   * `ownerOnly` in v0.1.x so default is a no-op for legacy callers).
   */
  isOwner?: boolean;
  /**
   * v0.2.0 — Current plan-tier seat capacity. Used by `minMembers` gate
   * (L45). Default `Infinity` (matches v0.1 behavior — no items have
   * `minMembers` in v0.1.x so default is a no-op for legacy callers).
   */
  currentMaxMembers?: number;
  /**
   * v0.2.0 — When `true`, bypass ALL permission gates (permission /
   * ownerOnly / minMembers) at BOTH section AND item levels (Q21 +
   * re-validation Finding 4). `hidden: true` is unconditionally respected.
   * Default `false`.
   */
  bypassFiltering?: boolean;
}

/**
 * Filter and shape the items[] for render.
 *
 * Gating order per NavItem:
 *   1. hidden === true → drop (no diagnostic, ALWAYS respected — Q21)
 *   2. If !bypassFiltering: permission ∩ ownerOnly ∩ minMembers (L46)
 *
 * NavSection gates the same way at the section level (whole-group drop) —
 * `bypassFiltering` applies at BOTH levels coherently per Finding 4 from
 * the GATE 2 re-validation (else "section disappears, items remain"
 * inconsistency). Empty sections after item filter auto-hide unless
 * keepEmptySections.
 *
 * v0.1 callers (without isOwner / currentMaxMembers / bypassFiltering)
 * see byte-identical behavior because the new gates only fire when the
 * corresponding optional NavItem fields are present + the bypass flag is
 * false; defaults are explicit per Finding 5.
 */
export function deriveVisibleEntries(opts: DeriveOptions): VisibleEntriesResult {
  const {
    items,
    permissions,
    keepEmptySections = false,
    isOwner = false,
    currentMaxMembers = Infinity,
    bypassFiltering = false,
  } = opts;

  const out: NavEntry[] = [];
  const filteredByPermission: { item: NavItem; requiredPermission: string }[] = [];
  let totalItemCount = 0;
  let hiddenItemCount = 0;

  const passesItemGates = (item: NavItem): { pass: boolean; missingPermission?: string } => {
    if (bypassFiltering) return { pass: true };
    if (item.permission && !(permissions?.has(item.permission) ?? false)) {
      return { pass: false, missingPermission: item.permission };
    }
    if (item.ownerOnly && !isOwner) return { pass: false };
    if (item.minMembers !== undefined && currentMaxMembers < item.minMembers) {
      return { pass: false };
    }
    return { pass: true };
  };

  for (const entry of items) {
    if (entry.kind === "separator") {
      out.push(entry);
      continue;
    }

    if (entry.kind === "section") {
      const section = entry as NavSection;
      if (section.hidden) continue;
      // Section perm gate — also skipped by bypassFiltering per Finding 4.
      if (
        !bypassFiltering &&
        section.permission &&
        !(permissions?.has(section.permission) ?? false)
      ) {
        continue;
      }
      const visibleInner: NavItem[] = [];
      for (const child of section.items) {
        totalItemCount += 1;
        if (child.hidden) {
          hiddenItemCount += 1;
          continue;
        }
        const gate = passesItemGates(child);
        if (!gate.pass) {
          if (gate.missingPermission) {
            filteredByPermission.push({ item: child, requiredPermission: gate.missingPermission });
          }
          continue;
        }
        visibleInner.push(child);
      }
      if (visibleInner.length === 0 && !keepEmptySections) continue;
      out.push({ ...section, items: visibleInner });
      continue;
    }

    // Top-level NavItem
    const item = entry as NavItem;
    totalItemCount += 1;
    if (item.hidden) {
      hiddenItemCount += 1;
      continue;
    }
    const gate = passesItemGates(item);
    if (!gate.pass) {
      if (gate.missingPermission) {
        filteredByPermission.push({ item, requiredPermission: gate.missingPermission });
      }
      continue;
    }
    out.push(item);
  }

  return {
    entries: out,
    filteredByPermission,
    totalItemCount,
    hiddenItemCount,
  };
}

import type { NavEntry } from "../types";

/**
 * Linear focus-traversal slot in the keyboard nav sequence.
 *
 * - `kind: "section-header"` — a focusable section header (the section was
 *   declared `collapsible: true`). Non-collapsible section headers render
 *   as a static `<h6>` and are excluded from focus traversal (L37).
 * - `kind: "item"` — a NavItem row. `sectionId` is the parent section id
 *   when the item lives inside a section, or `null` for top-level items.
 *
 * The `id` field is the row's stable id (item.id or section.id) and is
 * what the reducer's `FOCUS_ITEM` action stores.
 */
export interface SidebarKeyboardEntry {
  id: string;
  kind: "section-header" | "item";
  sectionId: string | null;
}

/**
 * Flatten the rendered NavEntry tree into the keyboard traversal sequence.
 *
 * Rules (per plan §17.2 + L37):
 *  - Separators are skipped.
 *  - Collapsible section headers are included; non-collapsible headers are
 *    not focusable so they're omitted.
 *  - When a section is collapsed, its items are not in the sequence.
 *  - Disabled items are skipped (they're not interactive).
 */
export function flattenEntriesForKeyboard(
  entries: ReadonlyArray<NavEntry>,
  collapsedSectionIds: ReadonlySet<string>,
): ReadonlyArray<SidebarKeyboardEntry> {
  const out: SidebarKeyboardEntry[] = [];
  for (const entry of entries) {
    if (entry.kind === "separator") continue;
    if (entry.kind === "section") {
      if (entry.collapsible) {
        out.push({ id: entry.id, kind: "section-header", sectionId: entry.id });
      }
      if (collapsedSectionIds.has(entry.id)) continue;
      for (const child of entry.items) {
        if (child.disabled) continue;
        out.push({ id: child.id, kind: "item", sectionId: entry.id });
      }
      continue;
    }
    if (entry.disabled) continue;
    out.push({ id: entry.id, kind: "item", sectionId: null });
  }
  return out;
}

import type { NavItem } from "../types";

export interface HrefResolverOpts {
  templateValues?: Record<string, string>;
  resolveHref?: (item: NavItem, values: Record<string, string> | undefined) => string;
}

/**
 * Resolve a NavItem's href to its final string form (v0.2.0).
 *
 * Precedence per L43:
 *   1. `resolveHref` callback (if provided) — return value is final
 *   2. `{key}` substitution from `templateValues` (when item.href has placeholders)
 *   3. `item.href` as-is
 *
 * Returns `undefined` when the item has no href (consumer rendered as label).
 *
 * Dev-mode warns when `item.href` references `{xxx}` placeholders not present
 * in `templateValues` (Q19; missing-only — unused values are common and
 * silently ignored). Warning is NODE_ENV-gated so it tree-shakes from prod
 * bundles.
 */
export function resolveItemHref(
  item: NavItem,
  opts: HrefResolverOpts,
): string | undefined {
  const { templateValues, resolveHref } = opts;

  if (resolveHref) {
    return resolveHref(item, templateValues);
  }

  if (!item.href) return undefined;
  if (!templateValues) return item.href;

  return substituteTemplate(item.href, templateValues);
}

/**
 * Set-based dedup per re-validation Finding 3 — distinct placeholders
 * trigger ONE `replaceAll` call each + one dev-warn entry each, regardless
 * of how many times the placeholder appears in the href.
 */
function substituteTemplate(
  href: string,
  values: Record<string, string>,
): string {
  const placeholders = new Set<string>();
  for (const [, key] of href.matchAll(/\{([^}]+)\}/g)) {
    placeholders.add(key);
  }
  if (placeholders.size === 0) return href;

  const missingKeys = new Set<string>();
  let result = href;
  for (const key of placeholders) {
    if (key in values) {
      result = result.replaceAll(`{${key}}`, values[key]!);
    } else if (process.env.NODE_ENV !== "production") {
      missingKeys.add(key);
    }
  }

  if (missingKeys.size > 0 && process.env.NODE_ENV !== "production") {
    console.warn(
      `[rich-sidebar] href "${href}" references placeholder${missingKeys.size === 1 ? "" : "s"} ` +
        `{${Array.from(missingKeys).join("}, {")}} not present in hrefTemplateValues. ` +
        `Substitution skipped for missing keys.`,
    );
  }

  return result;
}

import type { KeyboardEvent } from "react";
import type { SidebarKeyboardEntry } from "./flatten-entries";

export interface SidebarKeyboardContext {
  flat: ReadonlyArray<SidebarKeyboardEntry>;
  focusedId: string | null;
  setFocusedId: (id: string) => void;
  toggleSection: (sectionId: string) => void;
  isSectionCollapsed: (sectionId: string) => boolean;
}

/**
 * Arrow/Home/End/Enter/Esc dispatch over the flattened keyboard sequence.
 *
 * Behaviors (plan §17.2 + L37):
 *  - ArrowDown / ArrowUp — move focus across the sequence (wraps at edges).
 *  - Home / End — jump to first / last entry.
 *  - ArrowRight on a collapsed section header → expand.
 *  - ArrowLeft on an expanded section header → collapse.
 *  - Enter / Space — left to native button/link click on the focused row.
 *
 * The handler only updates the reducer's focusedItemId; the host effect in
 * `<RichSidebar>` programmatically focuses the matching DOM node on each
 * change so screen reader + keyboard user expectations line up.
 */
export function handleSidebarKeydown(
  event: KeyboardEvent,
  ctx: SidebarKeyboardContext,
): void {
  const { flat, focusedId, setFocusedId, toggleSection, isSectionCollapsed } = ctx;
  if (flat.length === 0) return;

  const currentIdx = focusedId ? flat.findIndex((e) => e.id === focusedId) : -1;

  switch (event.key) {
    case "ArrowDown": {
      event.preventDefault();
      const next =
        currentIdx >= 0 && currentIdx + 1 < flat.length
          ? flat[currentIdx + 1]
          : flat[0];
      setFocusedId(next.id);
      return;
    }
    case "ArrowUp": {
      event.preventDefault();
      const prev =
        currentIdx > 0 ? flat[currentIdx - 1] : flat[flat.length - 1];
      setFocusedId(prev.id);
      return;
    }
    case "Home": {
      event.preventDefault();
      setFocusedId(flat[0].id);
      return;
    }
    case "End": {
      event.preventDefault();
      setFocusedId(flat[flat.length - 1].id);
      return;
    }
    case "ArrowRight": {
      if (currentIdx < 0) return;
      const current = flat[currentIdx];
      if (current.kind === "section-header" && isSectionCollapsed(current.id)) {
        event.preventDefault();
        toggleSection(current.id);
      }
      return;
    }
    case "ArrowLeft": {
      if (currentIdx < 0) return;
      const current = flat[currentIdx];
      if (current.kind === "section-header" && !isSectionCollapsed(current.id)) {
        event.preventDefault();
        toggleSection(current.id);
      }
      return;
    }
  }
}

import type { RichSidebarMobileOpenReason } from "../types";

// ─────────────────────────────────────────────────────────────────────────
// Internal reducer state + actions
// (Internal shape — NOT exported via index.ts. Consumers interact with the
// component via the imperative handle + public RichSidebarStateValue.)
// ─────────────────────────────────────────────────────────────────────────

export interface SidebarReducerState {
  collapsed: boolean;
  mobileOpen: boolean;
  collapsedSectionIds: ReadonlySet<string>;
  focusedItemId: string | null;
  // L7 Defense-2 content-equality short-circuit anchor for EXTERNAL_SYNC.
  // Updated only on EXTERNAL_SYNC; never on internal transitions.
  lastSyncedSnapshot: {
    collapsed: boolean;
    mobileOpen: boolean;
  };
}

export type SidebarReducerAction =
  | { type: "SET_COLLAPSED"; collapsed: boolean }
  | { type: "TOGGLE_COLLAPSED" }
  | { type: "SET_MOBILE_OPEN"; open: boolean; reason: RichSidebarMobileOpenReason }
  | { type: "TOGGLE_MOBILE" }
  | { type: "SET_SECTION_COLLAPSED"; sectionId: string; collapsed: boolean }
  | { type: "TOGGLE_SECTION"; sectionId: string }
  | { type: "EXPAND_ALL_SECTIONS"; allSectionIds: ReadonlyArray<string> }
  | { type: "COLLAPSE_ALL_SECTIONS"; allSectionIds: ReadonlyArray<string> }
  | { type: "FOCUS_ITEM"; itemId: string | null }
  | { type: "EXTERNAL_SYNC"; collapsed: boolean; mobileOpen: boolean }
  | { type: "REPLACE_STATE"; state: SidebarReducerState };

export interface SidebarReducerInitOptions {
  defaultCollapsed?: boolean;
  defaultMobileOpen?: boolean;
  defaultCollapsedSectionIds?: ReadonlyArray<string>;
}

export function createInitialState(
  options: SidebarReducerInitOptions = {},
): SidebarReducerState {
  const collapsed = options.defaultCollapsed ?? false;
  const mobileOpen = options.defaultMobileOpen ?? false;
  return {
    collapsed,
    mobileOpen,
    collapsedSectionIds: new Set(options.defaultCollapsedSectionIds ?? []),
    focusedItemId: null,
    lastSyncedSnapshot: { collapsed, mobileOpen },
  };
}

export function sidebarReducer(
  state: SidebarReducerState,
  action: SidebarReducerAction,
): SidebarReducerState {
  switch (action.type) {
    case "SET_COLLAPSED":
      if (state.collapsed === action.collapsed) return state;
      return { ...state, collapsed: action.collapsed };

    case "TOGGLE_COLLAPSED":
      return { ...state, collapsed: !state.collapsed };

    case "SET_MOBILE_OPEN":
      if (state.mobileOpen === action.open) return state;
      return { ...state, mobileOpen: action.open };

    case "TOGGLE_MOBILE":
      return { ...state, mobileOpen: !state.mobileOpen };

    case "SET_SECTION_COLLAPSED": {
      const has = state.collapsedSectionIds.has(action.sectionId);
      if (action.collapsed && has) return state;
      if (!action.collapsed && !has) return state;
      const next = new Set(state.collapsedSectionIds);
      if (action.collapsed) next.add(action.sectionId);
      else next.delete(action.sectionId);
      return { ...state, collapsedSectionIds: next };
    }

    case "TOGGLE_SECTION": {
      const next = new Set(state.collapsedSectionIds);
      if (next.has(action.sectionId)) next.delete(action.sectionId);
      else next.add(action.sectionId);
      return { ...state, collapsedSectionIds: next };
    }

    case "EXPAND_ALL_SECTIONS":
      if (state.collapsedSectionIds.size === 0) return state;
      return { ...state, collapsedSectionIds: new Set() };

    case "COLLAPSE_ALL_SECTIONS": {
      const next = new Set(action.allSectionIds);
      // No-op if identical (rare)
      if (
        next.size === state.collapsedSectionIds.size &&
        [...next].every((id) => state.collapsedSectionIds.has(id))
      ) {
        return state;
      }
      return { ...state, collapsedSectionIds: next };
    }

    case "FOCUS_ITEM":
      if (state.focusedItemId === action.itemId) return state;
      return { ...state, focusedItemId: action.itemId };

    case "EXTERNAL_SYNC": {
      // L7 Defense 2: content-equality short-circuit
      if (
        state.lastSyncedSnapshot.collapsed === action.collapsed &&
        state.lastSyncedSnapshot.mobileOpen === action.mobileOpen
      ) {
        return state;
      }
      return {
        ...state,
        collapsed: action.collapsed,
        mobileOpen: action.mobileOpen,
        lastSyncedSnapshot: {
          collapsed: action.collapsed,
          mobileOpen: action.mobileOpen,
        },
      };
    }

    case "REPLACE_STATE":
      return action.state;

    default: {
      // Exhaustive check — TypeScript flags unhandled action types at compile time
      const _exhaustive: never = action;
      void _exhaustive;
      return state;
    }
  }
}

/**
 * Versioned schema for localStorage persistence (L23).
 *
 * Bump STORAGE_SCHEMA_VERSION when the shape changes; the type-guard
 * silently drops mismatched payloads so older data doesn't corrupt the
 * runtime state.
 */
export const STORAGE_SCHEMA_VERSION = 1;

export interface StoredState {
  v: 1;
  collapsed: boolean;
  collapsedSectionIds: string[];
}

export function isStoredState(value: unknown): value is StoredState {
  if (typeof value !== "object" || value === null) return false;
  const v = value as Partial<StoredState>;
  return (
    v.v === STORAGE_SCHEMA_VERSION &&
    typeof v.collapsed === "boolean" &&
    Array.isArray(v.collapsedSectionIds) &&
    v.collapsedSectionIds.every((id) => typeof id === "string")
  );
}

import { forwardRef } from "react";
import type { NavLinkProps } from "../types";

/**
 * Default linkComponent — vanilla `<a href>` wrapper.
 *
 * Consumers using Next.js / React Router / TanStack Router pass their own
 * linkComponent. See usage.tsx for one-liner adapters.
 */
export const DefaultLink = forwardRef<HTMLAnchorElement, NavLinkProps>(
  function DefaultLink({ href, children, ...rest }, ref) {
    return (
      <a ref={ref} href={href} {...rest}>
        {children}
      </a>
    );
  },
);

import { isValidElement, type ComponentType, type ReactNode } from "react";
import { cn } from "@/lib/utils";

interface IconProps {
  icon: ReactNode | ComponentType<{ className?: string }> | undefined;
  className?: string;
}

/**
 * Renders either:
 *  - a React component (e.g., lucide-react `Home`) — invoked with className
 *  - a ReactNode (JSX element, string emoji, image, custom mark) — rendered as-is
 *  - undefined — renders nothing
 *
 * Convention: icon components receive a className with sizing (`h-5 w-5` or
 * similar). ReactNode icons are expected to size themselves.
 */
export function Icon({ icon, className }: IconProps) {
  if (icon === undefined || icon === null) return null;

  if (isValidElement(icon)) {
    return <>{icon}</>;
  }

  // Plain function components AND forwardRef objects (lucide-react icons in
  // v0.475+ ship as `forwardRef` objects whose typeof === "object", not
  // "function" — the previous typeof-only check rendered the object as a
  // child and crashed the static-prerender path).
  const isComponentObject =
    typeof icon === "object" && icon !== null && "$$typeof" in icon;
  if (typeof icon === "function" || isComponentObject) {
    const IconComponent = icon as ComponentType<{ className?: string }>;
    return <IconComponent className={cn("h-5 w-5 shrink-0", className)} />;
  }

  // String / number / fragment — render as-is
  return <>{icon}</>;
}

