import { cn } from "@/lib/utils";

interface SidebarLoadingSkeletonProps {
  isCollapsed: boolean;
  rowCount?: number;
  className?: string;
}

/**
 * Default loading skeleton — 6 shimmer rows by default.
 *
 * Width matches sidebar's collapsed/expanded mode automatically (inherits
 * the parent <nav>'s width). Shimmer animation gated motion-safe;
 * reduced-motion users see static muted rows.
 *
 * Override entirely via the `renderLoading` slot (L13 priority).
 */
export function SidebarLoadingSkeleton({
  isCollapsed,
  rowCount = 6,
  className,
}: SidebarLoadingSkeletonProps) {
  return (
    <ul
      role="list"
      aria-busy="true"
      aria-label="Loading navigation items"
      className={cn("flex flex-col gap-1", className)}
    >
      {Array.from({ length: rowCount }, (_, i) => (
        <li key={i} className="list-none">
          <div
            className={cn(
              "flex items-center gap-3 rounded-lg px-3 py-2.5",
              "motion-safe:animate-pulse",
            )}
            aria-hidden="true"
          >
            <span className="h-5 w-5 shrink-0 rounded-md bg-muted" />
            {!isCollapsed && (
              <span
                className="h-4 rounded bg-muted"
                style={{
                  // Vary the width slightly so the skeleton looks real
                  width: `${60 + ((i * 7) % 30)}%`,
                }}
              />
            )}
          </div>
        </li>
      ))}
    </ul>
  );
}

"use client";

import { Fragment } from "react";
import { cn } from "@/lib/utils";
import type {
  NavEntry,
  NavItem,
  NavLinkComponent,
  RichSidebarEventArgs,
  RichSidebarProps,
} from "../types";
import { SidebarNavRow } from "./sidebar-nav-row";
import { SidebarNavSection } from "./sidebar-nav-section";
import { SidebarNavSeparator } from "./sidebar-nav-separator";

interface SidebarNavListProps {
  entries: ReadonlyArray<NavEntry>;
  activeItemId: string | null;
  focusedItemId: string | null;
  /**
   * Stable id of the first focusable item/section header in the rendered
   * traversal — used as the roving tabindex anchor when nothing is focused.
   * Null if no row is focusable (loading / empty).
   */
  keyboardEntryId: string | null;
  isCollapsed: boolean;
  linkComponent: NavLinkComponent;
  activeVariant?: RichSidebarProps["activeVariant"];
  autoCloseMobileOnNavigate: boolean;
  isMobileOpen: boolean;
  onCloseMobile: () => void;

  // Section state — driven by reducer in parent
  collapsedSectionIds: ReadonlySet<string>;
  onToggleSection: (sectionId: string) => void;

  // Consumer event hooks
  onItemClick?: (args: RichSidebarEventArgs["itemClick"]) => void;
  onItemNavigate?: (args: RichSidebarEventArgs["itemNavigate"]) => void;
  onSectionToggle?: (args: RichSidebarEventArgs["sectionToggle"]) => void;

  // Slot priority
  renderItem?: RichSidebarProps["renderItem"];
  renderSection?: RichSidebarProps["renderSection"];
  renderBadge?: RichSidebarProps["renderBadge"];
  renderTooltipContent?: RichSidebarProps["renderTooltipContent"];

  // v0.2.0 — href resolution (L42 + L43)
  hrefTemplateValues?: RichSidebarProps["hrefTemplateValues"];
  resolveHref?: RichSidebarProps["resolveHref"];
}

/**
 * Renders the NavEntry[] list — flat NavItems, NavSections, and NavSeparators.
 *
 * C3 surface: flat items + separators. Sections render their items in a
 * single ungrouped list (full section UI with title + collapsible header
 * lands C4 in parts/sidebar-nav-section.tsx).
 *
 * Click sequence per L28:
 *   1. consumer's item.onClick fires sync
 *   2. onItemClick (component-level) fires sync
 *   3. if event.defaultPrevented → stop
 *   4. queueMicrotask → onItemNavigate + autoCloseMobileOnNavigate
 *
 * Disabled items short-circuit at step 1 (L27).
 */
export function SidebarNavList({
  entries,
  activeItemId,
  focusedItemId,
  keyboardEntryId,
  isCollapsed,
  linkComponent,
  activeVariant,
  autoCloseMobileOnNavigate,
  isMobileOpen,
  onCloseMobile,
  collapsedSectionIds,
  onToggleSection,
  onItemClick,
  onItemNavigate,
  onSectionToggle,
  renderItem,
  renderSection,
  renderBadge,
  renderTooltipContent,
  hrefTemplateValues,
  resolveHref,
}: SidebarNavListProps) {
  // Roving tabindex (L37). The "entry point" rule:
  //   - Some row has the user's focus      → only that row is tabbable.
  //   - Nothing focused yet                 → the keyboard entry row is tabbable.
  //   - Disabled items always pass to -1.
  const resolveRovingTabIndex = (itemId: string): 0 | -1 => {
    if (focusedItemId) return focusedItemId === itemId ? 0 : -1;
    return keyboardEntryId === itemId ? 0 : -1;
  };
  const handleItemClick =
    (item: NavItem, sectionId: string | null, indexInSection: number) =>
    (event: React.MouseEvent) => {
      // L27 — disabled items short-circuit at step 1
      if (item.disabled) {
        event.preventDefault();
        return;
      }
      // Step 1 — consumer's per-item onClick
      item.onClick?.(event);
      // Step 2 — component-level onItemClick
      onItemClick?.({ item, isActive: activeItemId === item.id, event });
      // Step 3 — short-circuit if cancelled
      if (event.defaultPrevented) return;
      // Step 4 — microtask defer the navigation-side effects
      queueMicrotask(() => {
        onItemNavigate?.({ item });
        if (autoCloseMobileOnNavigate && isMobileOpen) {
          onCloseMobile();
        }
      });
      // Intentionally allow native <a> navigation to proceed unless
      // consumer called preventDefault in step 1 or 2.
      void sectionId;
      void indexInSection;
    };

  // Renders a single NavItem row, honoring the renderItem slot (L13/L29).
  // Returns an `<li>` (either via <SidebarNavRow> itself or the renderItem
  // wrapper). The key lives on the returned element directly — callers must
  // NOT add an intermediate wrapper, since the parent is a <ul> and only
  // <li> can be a valid direct child.
  const renderRow = (item: NavItem, sectionId: string | null, indexInSection: number) => {
    const isActive = activeItemId === item.id;
    const isFocused = focusedItemId === item.id;
    const rovingTabIndex = resolveRovingTabIndex(item.id);
    const defaultRender = (
      <SidebarNavRow
        key={item.id}
        item={item}
        isActive={isActive}
        isCollapsed={isCollapsed}
        isFocused={isFocused}
        rovingTabIndex={rovingTabIndex}
        linkComponent={linkComponent}
        activeVariant={activeVariant}
        onClick={handleItemClick(item, sectionId, indexInSection)}
        renderBadge={renderBadge}
        renderTooltipContent={renderTooltipContent}
        hrefTemplateValues={hrefTemplateValues}
        resolveHref={resolveHref}
      />
    );
    if (!renderItem) return defaultRender;
    return (
      <li key={item.id} className="list-none">
        {renderItem({
          item,
          isActive,
          isCollapsed,
          isFocused,
          isDisabled: item.disabled ?? false,
          sectionId,
          indexInSection,
          defaultRender,
        })}
      </li>
    );
  };

  return (
    <ul
      role="list"
      className={cn(
        "flex flex-1 flex-col gap-1 overflow-y-auto",
        // C5 hooks: motion-safe transitions will live here
      )}
    >
      {entries.map((entry, i) => {
        if (entry.kind === "separator") {
          return <SidebarNavSeparator key={entry.id ?? `sep-${i}`} />;
        }
        if (entry.kind === "section") {
          const isSectionCollapsed = collapsedSectionIds.has(entry.id);
          const isSectionFocused = focusedItemId === entry.id;
          const sectionRovingTabIndex =
            entry.collapsible ? resolveRovingTabIndex(entry.id) : -1;
          const handleSectionToggle = () => {
            onToggleSection(entry.id);
            onSectionToggle?.({ section: entry, collapsed: !isSectionCollapsed });
          };
          const defaultSection = (
            <SidebarNavSection
              key={entry.id}
              section={entry}
              isCollapsed={isSectionCollapsed}
              isSidebarCollapsed={isCollapsed}
              visibleItemCount={entry.items.length}
              isFocused={isSectionFocused}
              rovingTabIndex={sectionRovingTabIndex}
              onToggle={handleSectionToggle}
            >
              {entry.items.map((child, idx) => renderRow(child, entry.id, idx))}
            </SidebarNavSection>
          );
          if (!renderSection) return defaultSection;
          // `renderSection` is expected to return an `<li>` (typically by
          // forwarding `defaultRender` or composing its own list-item).
          // Fragment carries the key without injecting an invalid DOM node
          // between the `<ul>` parent and the consumer's `<li>`.
          return (
            <Fragment key={entry.id}>
              {renderSection({
                section: entry,
                isCollapsed: isSectionCollapsed,
                visibleItemCount: entry.items.length,
                defaultRender: defaultSection,
              })}
            </Fragment>
          );
        }
        // Top-level NavItem — renderRow returns an `<li>` directly with
        // the key already applied, so no wrapper element is needed.
        return renderRow(entry, null, i);
      })}
    </ul>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { getActiveVariantClasses } from "../lib/active-variant-classes";
import { resolveItemHref } from "../lib/href-resolver";
import type {
  NavBadgeConfig,
  NavItem,
  NavLinkComponent,
  RichSidebarProps,
} from "../types";
import { Icon } from "./icon";
import { NavBadge } from "./nav-badge";
import { TooltipWrapper } from "./tooltip-wrapper";

interface SidebarNavRowProps {
  item: NavItem;
  isActive: boolean;
  isCollapsed: boolean;
  isFocused: boolean;
  /**
   * Roving tabindex (L37). `0` when this row is the keyboard entry point
   * (= focused row OR — when nothing is focused — the first focusable row);
   * `-1` otherwise. Disabled items always pass through to `tabIndex={-1}`.
   */
  rovingTabIndex: 0 | -1;
  linkComponent: NavLinkComponent;
  activeVariant?: RichSidebarProps["activeVariant"];
  onClick: (event: React.MouseEvent) => void;
  renderBadge?: RichSidebarProps["renderBadge"];
  renderTooltipContent?: RichSidebarProps["renderTooltipContent"];
  // v0.2.0 — href resolution (L42 + L43)
  hrefTemplateValues?: RichSidebarProps["hrefTemplateValues"];
  resolveHref?: RichSidebarProps["resolveHref"];
}

/**
 * Resolve a NavItem's badge config (shorthand number/string → full config).
 */
function resolveBadgeConfig(
  badge: NavItem["badge"],
): NavBadgeConfig | null {
  if (badge === undefined || badge === null) return null;
  if (typeof badge === "number" || typeof badge === "string") {
    return { value: badge };
  }
  // Already a NavBadgeConfig (or arbitrary ReactNode — treat as value)
  if (typeof badge === "object" && "value" in badge) {
    return badge as NavBadgeConfig;
  }
  // Bare ReactNode badge
  return { value: badge as NavBadgeConfig["value"] };
}

export function SidebarNavRow({
  item,
  isActive,
  isCollapsed,
  isFocused,
  rovingTabIndex,
  linkComponent: LinkComponent,
  activeVariant,
  onClick,
  renderBadge,
  renderTooltipContent,
  hrefTemplateValues,
  resolveHref,
}: SidebarNavRowProps) {
  const isDisabled = item.disabled ?? false;
  // v0.2.0: resolveItemHref applies the precedence pipeline (callback wins
  // over template-value substitution; fallback to item.href as-is). When
  // neither v0.2 prop is provided, this is byte-identical to v0.1 behavior.
  const resolvedHref = resolveItemHref(item, { templateValues: hrefTemplateValues, resolveHref });
  const href = resolvedHref ?? "#";

  const badgeConfig = resolveBadgeConfig(item.badge);
  const defaultBadge = badgeConfig ? (
    <NavBadge {...badgeConfig} />
  ) : null;
  const badgeNode = renderBadge && badgeConfig
    ? renderBadge({
        item,
        badge: badgeConfig,
        position: isCollapsed ? "corner" : "inline-end",
        defaultRender: defaultBadge,
      })
    : defaultBadge;

  // Tooltip content when collapsed — label + optional shortcut + optional description
  const tooltipContent = renderTooltipContent
    ? renderTooltipContent({ item, isActive })
    : (item.tooltipContent ?? (
        <div className="flex flex-col gap-0.5">
          <span className="font-medium">{item.label}</span>
          {item.shortcut && (
            <span className="text-[10px] text-muted-foreground">
              {item.shortcut}
            </span>
          )}
          {!isActive && item.description && (
            <span className="text-[10px] text-muted-foreground/90">
              {item.description}
            </span>
          )}
        </div>
      ));

  const linkEl = (
    <LinkComponent
      href={href}
      onClick={onClick}
      aria-current={isActive ? "page" : undefined}
      aria-label={isCollapsed ? item.label : undefined}
      aria-disabled={isDisabled || undefined}
      data-active={isActive}
      data-focused={isFocused || undefined}
      data-nav-id={item.id}
      tabIndex={isDisabled ? -1 : rovingTabIndex}
      target={item.target}
      rel={item.rel}
      className={cn(
        "group relative flex items-center gap-3 rounded-lg px-3 py-2.5",
        "text-sm font-medium",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-card",
        // Active vs inactive paint via L12 variant matrix
        getActiveVariantClasses(activeVariant, isActive),
        // Disabled (L27)
        isDisabled && "pointer-events-none cursor-not-allowed opacity-50",
        // Center icon when collapsed
        isCollapsed && "justify-center",
      )}
    >
      {(item.icon !== undefined && item.icon !== null) || isCollapsed ? (
        <span className="relative inline-flex h-5 w-5 shrink-0 items-center justify-center">
          {item.icon !== undefined && item.icon !== null ? (
            <Icon icon={item.icon} />
          ) : (
            // Fallback glyph when collapsed AND no explicit icon —
            // first letter of the label, styled like an icon. Keeps the
            // row visually anchored so the corner-badge has something to
            // sit on top of.
            <span
              aria-hidden="true"
              className="inline-flex h-5 w-5 items-center justify-center rounded-sm bg-muted text-[10px] font-semibold uppercase text-muted-foreground"
            >
              {item.label?.[0] ?? "•"}
            </span>
          )}
          {/* Badge in corner position when collapsed */}
          {isCollapsed && badgeNode}
        </span>
      ) : null}
      {!isCollapsed && (
        <span className="flex-1 truncate">{item.label}</span>
      )}
      {!isCollapsed && item.shortcut && (
        <span
          className={cn(
            "rounded px-1.5 py-0.5 font-mono text-xs",
            isActive ? "bg-primary-foreground/10" : "bg-muted text-muted-foreground",
          )}
        >
          {item.shortcut}
        </span>
      )}
      {!isCollapsed && item.accessory && (
        <span className="inline-flex items-center">{item.accessory}</span>
      )}
      {/* Badge in inline-end position when expanded */}
      {!isCollapsed && badgeNode}
    </LinkComponent>
  );

  return (
    <li className={cn("list-none", item.className)} data-testid={item["data-testid"]}>
      <TooltipWrapper
        content={tooltipContent}
        side="right"
        disabled={!isCollapsed}
      >
        {linkEl}
      </TooltipWrapper>
    </li>
  );
}

"use client";

import { ChevronDown } from "lucide-react";
import { useId } from "react";
import { cn } from "@/lib/utils";
import type { NavSection } from "../types";
import { Icon } from "./icon";

interface SidebarNavSectionProps {
  section: NavSection;
  isCollapsed: boolean; // section's own collapse state (NOT sidebar's)
  isSidebarCollapsed: boolean; // sidebar collapsed = icon-only mode
  visibleItemCount: number;
  isFocused: boolean;
  /** Roving tabindex for the collapsible header button (L37). */
  rovingTabIndex: 0 | -1;
  children: React.ReactNode; // the section's items (already rendered by parent)
  onToggle: () => void;
}

/**
 * Section header + collapsible body wrapper.
 *
 * Behavior:
 *  - collapsible=true → header is a <button aria-expanded aria-controls> that toggles
 *  - collapsible=false → header is a <h6 role="heading"> (label only, not focusable)
 *
 * At sidebar-collapsed mode (icon-only), section title hides; only the icon
 * shows. If section has no icon, the section header collapses to a thin
 * separator-like divider so groups remain visually distinct.
 */
export function SidebarNavSection({
  section,
  isCollapsed,
  isSidebarCollapsed,
  visibleItemCount,
  isFocused,
  rovingTabIndex,
  children,
  onToggle,
}: SidebarNavSectionProps) {
  const bodyId = useId();
  const collapsible = section.collapsible ?? false;

  // Sidebar at icon-only mode: render condensed
  if (isSidebarCollapsed) {
    return (
      <li className="list-none">
        {section.icon || section.title ? (
          <div className="px-3 py-1.5" role="presentation" aria-hidden="true">
            {section.icon ? (
              <Icon
                icon={section.icon}
                className="h-3.5 w-3.5 text-muted-foreground"
              />
            ) : (
              <div className="h-px w-full bg-border" />
            )}
          </div>
        ) : (
          <div className="my-1 h-px w-full bg-border" role="presentation" />
        )}
        {!isCollapsed && (
          // <ul> (not <div>) so the `<li>` rows produced by SidebarNavRow
          // are valid direct children. Outer wrapper is also <li> (section
          // root), so the structure is <li><ul><li>...</li></ul></li> —
          // valid HTML for a nested list group.
          <ul
            id={bodyId}
            role="group"
            aria-label={section.title}
            className="flex flex-col gap-1"
          >
            {children}
          </ul>
        )}
      </li>
    );
  }

  // Expanded sidebar — full section UI
  const headerInner = (
    <span className="flex flex-1 items-center gap-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
      {section.icon && <Icon icon={section.icon} className="h-3.5 w-3.5" />}
      <span className="truncate">{section.title}</span>
      {visibleItemCount > 0 && (
        <span
          className="ml-1 text-[10px] font-normal text-muted-foreground/70"
          aria-hidden="true"
        >
          {visibleItemCount}
        </span>
      )}
    </span>
  );

  return (
    <li className="list-none">
      {collapsible ? (
        <button
          type="button"
          onClick={onToggle}
          aria-expanded={!isCollapsed}
          aria-controls={bodyId}
          data-nav-id={section.id}
          data-focused={isFocused || undefined}
          tabIndex={rovingTabIndex}
          className={cn(
            "flex w-full items-center gap-2 rounded-md px-3 py-1.5 text-left",
            "hover:bg-muted/50",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-card",
          )}
        >
          {headerInner}
          <ChevronDown
            className={cn(
              "h-3.5 w-3.5 text-muted-foreground",
              "motion-safe:transition-transform motion-safe:duration-200",
              isCollapsed && "-rotate-90",
              // RTL: chevron rotates the OTHER way when collapsed so it
              // still points "outward" from the open direction
              isCollapsed && "rtl:rotate-90",
            )}
            aria-hidden="true"
          />
        </button>
      ) : section.title ? (
        // Non-collapsible header — pure label, not focusable
        <h6 className="px-3 py-1.5">{headerInner}</h6>
      ) : null}

      {!isCollapsed && (
        <ul
          id={bodyId}
          role="group"
          aria-label={section.title}
          className="mt-0.5 flex flex-col gap-1"
        >
          {children}
        </ul>
      )}
    </li>
  );
}

