"use client";

import { PanelLeft } from "lucide-react";
import { Slot } from "radix-ui";
import { cn } from "@/lib/utils";
import { useRichSidebarContextOrNull } from "../contexts/sidebar-nav-context";
import type { RichSidebarHandle, RichSidebarTriggerProps } from "../types";

/**
 * Companion trigger — mount in your app header to open the mobile drawer.
 *
 * Resolution order (L17 + L40):
 *   1. Explicit `controls` ref/handle (escape hatch) — wins
 *   2. Nearest RichSidebarContext (works when trigger is a DESCENDANT
 *      of <RichSidebar>; siblings can't read it because the context
 *      provider sits inside the sidebar's own render tree)
 *   3. Neither → dev-only console.warn + no-op
 *
 * Resolution happens at CLICK TIME, not render time, because the ref's
 * `.current` populates after the sidebar's `useImperativeHandle` runs
 * (post-mount). Resolving at render time would see `null` on first paint.
 *
 * Visual: hamburger icon (PanelLeft) — opens the drawer. Closing is
 * handled by the drawer's own SheetContent close-X (shipped by shadcn's
 * Sheet primitive) + Esc + outside-click. The trigger button itself
 * does NOT flip its icon based on drawer state — keeps the component
 * stateless and avoids the cross-tree re-render problem for v0.1.
 * A future RichSidebarProvider wrapper will enable trigger state
 * reflection across React subtrees if needed.
 *
 * Override the icon entirely via `children` (custom node) or `asChild`
 * (compose onto consumer's own element via Radix Slot).
 */
export function RichSidebarTrigger({
  controls,
  className,
  children,
  "aria-label": ariaLabel,
  asChild = false,
}: RichSidebarTriggerProps) {
  const ctx = useRichSidebarContextOrNull();

  const handleClick = () => {
    // Resolve handle at click time (not render time) — ref.current may
    // still be null on first render before useImperativeHandle runs.
    let resolved: RichSidebarHandle | null = null;
    if (controls) {
      if (typeof controls === "object" && controls !== null && "current" in controls) {
        resolved = (controls as React.RefObject<RichSidebarHandle | null>).current;
      } else {
        resolved = controls as RichSidebarHandle;
      }
    }
    if (!resolved && ctx) {
      resolved = ctx.handle;
    }
    if (resolved) {
      resolved.toggleMobile();
    } else if (process.env.NODE_ENV !== "production") {
      // eslint-disable-next-line no-console
      console.warn(
        "[rich-sidebar] <RichSidebarTrigger> clicked with no <RichSidebar> in context and no `controls` prop — no-op.",
      );
    }
  };

  const sidebarId = ctx?.sidebarId;

  const triggerProps = {
    type: "button" as const,
    onClick: handleClick,
    "aria-controls": sidebarId,
    "aria-haspopup": "dialog" as const,
    "aria-label": ariaLabel ?? "Open navigation",
    className: cn(
      !asChild &&
        "inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
      className,
    ),
  };

  if (asChild) {
    return <Slot.Root {...triggerProps}>{children}</Slot.Root>;
  }

  return (
    <button {...triggerProps}>
      {children ?? <PanelLeft className="h-4 w-4" aria-hidden="true" />}
    </button>
  );
}

"use client";

import { cn } from "@/lib/utils";
import type { RichSidebarEventArgs } from "../types";

interface SidebarSkipLinkProps {
  target: string;
  label: string;
  onActivated?: (args: RichSidebarEventArgs["skipLinkActivated"]) => void;
}

/**
 * Opt-in skip link (L31). Hidden until focused; appears at the top of the
 * sidebar's stacking context on keyboard focus. Activating jumps focus /
 * scroll to the consumer-supplied `skipLinkTarget` (e.g. `#main-content`).
 *
 * The component intentionally renders a plain `<a>` — using the consumer's
 * `linkComponent` for an in-page anchor would risk SPA frameworks treating
 * it as a route change. Native anchor behavior is the right primitive.
 */
export function SidebarSkipLink({
  target,
  label,
  onActivated,
}: SidebarSkipLinkProps) {
  return (
    <a
      href={target}
      data-sidebar-skip-link
      onClick={(event) => onActivated?.({ event })}
      className={cn(
        // sr-only by default — appears on focus
        "sr-only focus:not-sr-only",
        "focus:absolute focus:left-2 focus:top-2 focus:z-50",
        // RTL: skip link should sit on the same logical inline-start edge,
        // which means physical-right when direction is RTL
        "rtl:focus:left-auto rtl:focus:right-2",
        "focus:inline-flex focus:items-center focus:rounded-md",
        "focus:bg-card focus:px-3 focus:py-2",
        "focus:text-sm focus:font-medium focus:text-foreground",
        "focus:shadow-md focus:ring-1 focus:ring-border",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-card",
      )}
    >
      {label}
    </a>
  );
}

"use client";

import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

interface TooltipWrapperProps {
  content: React.ReactNode;
  children: React.ReactNode;
  side?: "right" | "top" | "bottom" | "left";
  disabled?: boolean;
  delay?: number;
}

/**
 * F-cross-13 defensive Tooltip wrapper (L19 + R7).
 *
 * Producer ships Radix-based primitive (delayDuration); consumer-installed
 * shadcn 4.6+ may ship Base UI primitive (delay). Pass BOTH prop names —
 * the unused one is silently ignored by the underlying implementation.
 *
 * When `disabled` is true (e.g., expanded sidebar mode), children render
 * without the Tooltip wrapper at all — saves Provider mount cost.
 */
export function TooltipWrapper({
  content,
  children,
  side = "right",
  disabled,
  delay = 300,
}: TooltipWrapperProps) {
  if (disabled) return <>{children}</>;

  return (
    <TooltipProvider
      delayDuration={delay}
      // @ts-expect-error — Base UI primitives use `delay` prop name; Radix uses
      // `delayDuration`. Pass both defensively per F-cross-13 (memory:
      // project_shadcn_primitive_radix_baseui_divergence). The unused prop is
      // ignored at runtime.
      delay={delay}
    >
      <Tooltip>
        <TooltipTrigger asChild>{children}</TooltipTrigger>
        <TooltipContent side={side} className="z-50">
          {content}
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}
